#include <iostream>
#include <string>
using namespace std;

class Person {
protected:
 string name;
 int age;
public:
 Person(string n, int a) : name(n), age(a) {
 cout << "Person constructor called" << endl;
 }
 void displayPerson() {
 cout << "Name: " << name << ", Age: " << age << endl;
 }
 ~Person() {
 cout << "Person destructor called" << endl;
 }
};

class Student {
protected:
 int rollNo;
 float marks;
public:
 Student(int r, float m) : rollNo(r), marks(m) {
 cout << "Student constructor called" << endl;
 }
 void displayStudent() {
 cout << "Roll No: " << rollNo << ", Marks: " << marks << endl;
 }
 ~Student() {
 cout << "Student destructor called" << endl;
 }
};

class CollegeStudent : public Person, public Student {
private:
 string college;
public:
 CollegeStudent(string n, int a, int r, float m, string c)
 : Person(n, a), Student(r, m), college(c) {
 cout << "CollegeStudent constructor called" << endl;
 }
 void display() {
 displayPerson();
 displayStudent();
 cout << "College: " << college << endl;
 }
 ~CollegeStudent() {
 cout << "CollegeStudent destructor called" << endl;
 }
};

int main() {
 CollegeStudent cs("John", 20, 101, 85.5, "university College");
 cs.display();
 return 0;
}

#include <iostream>
using namespace std;

class A {
public:
 int data = 10;
 void show() {
 cout << "A's show() called, data = " << data << endl;
 }
};

class B : public A {
public:
 void display() {
 cout << "B's display()" << endl;
 }
};

class C : public A {
public:
 void display() {
 cout << "C's display()" << endl;
 }
};

class D : public B, public C {
public:
 void showD() {
 // Ambiguous - which A's data?
 // B::show(); // Uncomment to resolve
 // C::show(); // Uncomment to resolve
 cout << "D's showD()" << endl;
 }
};

int main() {
 D obj;
 // obj.show(); // ERROR: ambiguous - B::A::show() or C::A::show()?
 obj.B::show(); // Explicitly call A's show through B
 obj.C::show(); // Explicitly call A's show through C
 cout << "B::data: " << obj.B::data << endl;
 cout << "C::data: " << obj.C::data << endl;
 return 0;
}

#include <iostream>
using namespace std;

class A {
public:
 int data = 10;
 A() {
 cout << "A constructor called" << endl;
 }
 A(int d) : data(d) {
 cout << "A constructor with arg called" << endl;
 }
 void show() {
 cout << "A's show() called, data = " << data << endl;
 }
};

// Virtual inheritance - A is now a virtual base class
class B : virtual public A {
public:
 B() {
 cout << "B constructor called" << endl;
 }
};

class C : virtual public A {
public:
 C() {
 cout << "C constructor called" << endl;
 }
};

class D : public B, public C {
public:
 // Most derived class - initializes virtual base A
 D() {
 cout << "D constructor called" << endl;
 }
 D(int d) : A(d) { // A initialized by D (most derived)
 cout << "D constructor with arg called" << endl;
 }
 void showD() {
 show(); // No ambiguity - only one A exists
 cout << "data = " << data << endl; // Direct access now works
 }
};

int main() {
 cout << "--- Creating D obj1 --- " << endl;
 D obj1;
 obj1.showD();

 cout << "\n--- Creating D obj2 with data=99 --- " << endl;
 D obj2(99);
 obj2.showD();
 return 0;
}

#include <iostream>
using namespace std;

class Base1 {
public:
 int x = 5;
 void display() {
 cout << "Base1's display: x = " << x << endl;
 }
};

class Base2 {
public:
 int x = 15; // Same member name
 void display() {
 cout << "Base2's display: x = " << x << endl;
 }
};

class Derived : public Base1, public Base2 {
public:
 void show() {
 // Ambiguous - which x?
 // cout << x; // ERROR: request for member 'x' is ambiguous

 // Resolution using scope resolution operator
 cout << "Base1.x = " << Base1::x << endl;
 cout << "Base2.x = " << Base2::x << endl;

 // Calling specific display methods
 Base1::display();
 Base2::display();
 }
};

int main() {
 Derived d;
 d.show();
 return 0;
}
